_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vUv = vUvOriginal;
uv1 = (vUv-.5) * uAspect.xy;

//GOLD
float z = 8*length(uv1)+uTime;
vec2 uvn =normalize(uv1);
rs = clamp(tan(z)*uvn,-5,5)/3;

// KUGEL
vec2 p0 = vec2(q9,q10);
ball = uv1 - p0;
float size = .015;
float dist = length(ball)  / size;
z = clamp01(1-dist);

//ADD
float mask = (z >= .001);
rs = q28*rs + (1-q28)*rs.yx;
vUv += (1-mask)*.03*(rs.yx) + .6*mask*z*normalize(ball);


uv6 = multiply(uv1,mat2(_qb));
mus = (.12/(sqrt(uv6.x)));
mus = .08*abs(mus) - z* (.2 + .3*slow_roam_cos.xyz);

vec3 gold = vec3 (.1,.84,.6);

//vec2 uv2 = .7*uv1+.3*vec2 (sin(uv1.y*16), sin(uv1.x*16));
//uv2 *= .2;
//vec3 dots = q26*clamp01(.0015/(length(uv2)));

vec3 col = gold;

vec3 blur = GetBlur1(fract(vUv));
vec3 crisp= texture(sampler_main,vUv);

vec3 ret1 = crisp - blur*.03 + col*(mus);
ret = ret1*.99-.018;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vUv = (vUv-.5)*.9 + .5;
uv0 = vUv;

dist = MinDistB(vUv);
bdist = mix(dist,GetDistB(vUv),.2);
float focus = sat(abs(GetDistB(vUv)-dist_c)*3);

vec2 noise = texture(sampler_noise_mq,vec2(vUv.x,vUv.y/4-.1*uTime)).xy;
vUv += .004*bdist*noise ;
vec2 uv5 = (vUv-.5)*uAspect.xy  - vec2(q11,q12);
bubbles = 0; gmask = 0; anz = 3; bcentre = 0;
for (int m= 1; m<= anz; m++)
{
  z = 1-fract(1.0/anz*m+q9);
  uv1 = uv5*z;
//  uv1 = multiply(uv1, mat2(.7,.7,-.7,.7));

  grid = 16.0*m/512;

  slot = texture(sampler_pw_noise_lq,uv1.x*grid)+.5;
  uv1.y += slot*uTime*.06;
  bsize = texture(sampler_pw_noise_lq,uv1*grid);
  rsk = fract(8*m*uv1)-.5 ;
  dz = normalize(rsk);
  rad1 = 3*length(rsk) *(2+m);
  uv4 =  (rad1*rad1)*dz;
  mask1 = clamp01(29-8*rad1) * (bsize > .75) ;
  gmask = gmask || mask1;
  bubbles += vec3 (uv4,.1/(rad1)) * (1-z) * mask1;
}
gmask *= sat (bdist*16-8*z);
vUv +=  .1*bubbles*gmask;

dist = MinDistB(vUv);
bdist = mix(dist,GetDistB(vUv),.2);
dist_c = clamp(GetDistB2 (center),.1,.4); //center distance

float struc = GetBlurX(vUv,focus).r;

ret = struc* col_struc *vec3(1-bdist,1,1)+ pow(sat(struc),4) * vec3 (0,1,.2);
vec4 noise9 = texture3D(sampler_noisevol_hq,
                      ((vUv.xyy*q28
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1,1,0)*0.05 +
                      uTime*vec3(0,0,1)*q31
                     );
if(ret.x> q26*q13         && ret.x<= q23*q11        )ret.z -= (noise9).x*.5;
if(ret.y> q25*q11         && ret.y<= q22*q12        )ret.x -= (noise9).y*.5;
if(ret.z> q24*q12         && ret.z<= q21*q13        )ret.y -= (noise9).z*.5;


//distant light
ret += gmask*bubbles.z * (1+slow_roam_cos);

ret = mix(ret, vec3(0,.05,.1)*4*q19, sat(pow(bdist,1.5)));

float moon = (.5/length(sin(3*(uv5))));
ret += sat(MinDistB(vUv)*6-5)*moon*vec3(0,.1,.1);

//Lamp
uv3 = vUv-center;
float ddd = GetPixel(vUv).r - GetPixel((vUv-.5)*(1.01)+.5).r;
lamp = clamp01(1-4*length(uv3)) * (.1+struc+ddd);
ret += lamp*(clamp01(1-bdist/2))*(1-0*shadow(vUv)) * vec3(1,.8,.3);

ret = 1-exp((-6)*ret);
//ret += shadow(vUv);
//ret = GetPixel(uv0).r;

  fragColor = ret;
}
